  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasEquipment ?child ; p:hasClassroom ?parent . } GROUP BY ?child }
  ?child p:equipmentName ?equipmentname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Classrooms } }
